proof_block:
// Prove the determinism implication explicitly.  Both ensures-conjuncts
// are guarded by `!(. is InvalidMessage) ==> ...` and both pin the view
// of the result to the *same* spec witness `sht_demarshal_data(buffer@)@`.
// Inside `assert(... ==> ...) by { if antecedent { ... } }` we introduce
// the antecedent and case-split on the `InvalidMessage` discriminator of
// `r1` and `r2`; the shared spec witness then lines up the two runs'
// views and `=~=` lifts view-equality (which is what
// `CSingleMessage::view` encodes injectively on variant tag + each
// field's own view) to structural equality on `CSingleMessage` (and
// recursively on its `EndPoint`/`Vec<u8>`/`CMessage` payloads, all of
// which are determined by their views).
assert(
    ({
        &&& (!(r1 is InvalidMessage) ==> {
            &&& r1.is_marshalable()
            &&& r1@ == sht_demarshal_data(buffer@)@
            &&& r1.abstractable()
        })
        &&& (!(r2 is InvalidMessage) ==> {
            &&& r2.is_marshalable()
            &&& r2@ == sht_demarshal_data(buffer@)@
            &&& r2.abstractable()
        })
    }) ==> det_sht_demarshall_data_method_equal(r1, r2)
) by {
    if ({
        &&& (!(r1 is InvalidMessage) ==> {
            &&& r1.is_marshalable()
            &&& r1@ == sht_demarshal_data(buffer@)@
            &&& r1.abstractable()
        })
        &&& (!(r2 is InvalidMessage) ==> {
            &&& r2.is_marshalable()
            &&& r2@ == sht_demarshal_data(buffer@)@
            &&& r2.abstractable()
        })
    }) {
        let v = sht_demarshal_data(buffer@);
        if !(r1 is InvalidMessage) && !(r2 is InvalidMessage) {
            // Both ensures conjuncts fire, anchored on the shared `v@`.
            assert(r1@ == v@);
            assert(r2@ == v@);
            assert(r1@ == r2@);
            // `CSingleMessage::view` is injective on (variant tag,
            // field-wise view), and each field's spec type recovers
            // structural equality from view equality (u64/Seq/EndPoint/
            // CMessage all extensional via `=~=`).
            assert(r1 =~= r2);
        } else if (r1 is InvalidMessage) && (r2 is InvalidMessage) {
            // Both are the unit `InvalidMessage{}` variant.
            assert(r1 =~= r2);
        } else if (r1 is InvalidMessage) && !(r2 is InvalidMessage) {
            // `r2@ == v@` forces the spec witness `v` to *not* be the
            // InvalidMessage variant (since `r2@`'s discriminator is
            // Message/Ack).  Symmetrically, `r1@ == SingleMessage::
            // InvalidMessage{}` makes the variants disagree — this case
            // is incompatible with the ensures aligning on a common `v`.
            assert(r2@ == v@);
            assert(r1@ == SingleMessage::<Message>::InvalidMessage {});
        } else {
            // Symmetric mixed case.
            assert(r1@ == v@);
            assert(r2@ == SingleMessage::<Message>::InvalidMessage {});
        }
    }
};
